21	const PROCESSING_FEE = 5;
22	const BLOCK_SIZE = 3;
23	const COMPONENT_UNIT_PREMIUM = 25;
24	const COMPONENT_BLOCK_PREMIUM = 60;
25	const FIRST_INSURANCE_RATE = 0.1;
26	const LOYALTY_RATE = 0.2;
27	const LOYALTY_MIN_YEARS = 2;
28	const FOLLOW_UP_RATE = 0.15;
29	const CURSE_SURCHARGE_RATE = 0.5;
30	const HIGH_ENCHANTMENT_RATE = 0.3;
31	const HIGH_ENCHANTMENT_THRESHOLD = 5;
32	
33	const COMPONENT_TYPES = ["rune", "moonstone"];
34	
35	const BASE_PREMIUMS: Record<string, number> = {
36	  sword: 100,
37	  amulet: 60,
38	  staff: 80,
39	  potion: 40,
40	  rune: COMPONENT_UNIT_PREMIUM,
41	  moonstone: COMPONENT_UNIT_PREMIUM,
42	};
43	
44	const isComponent = (item: Item): boolean =>
45	  COMPONENT_TYPES.includes(item.type);
46	
47	const isMainItem = (item: Item): boolean => !isComponent(item);
48	
49	const unitPriceFor = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
50	
51	const sumOver = (items: Item[], valueOf: (item: Item) => number): number =>
52	  items.reduce((sum, item) => sum + valueOf(item), 0);
53	
54	const componentGroupPremium = (count: number): number =>
55	  count === BLOCK_SIZE ? COMPONENT_BLOCK_PREMIUM : count * COMPONENT_UNIT_PREMIUM;
56	
57	const countByType = (items: Item[]): Map<string, number> =>
58	  items.reduce((counts, item) => {
59	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
60	    return counts;
61	  }, new Map<string, number>());
62	
63	const componentsBasePremium = (items: Item[]): number =>
64	  [...countByType(items.filter(isComponent)).values()].reduce(
65	    (sum, count) => sum + componentGroupPremium(count),
66	    0
67	  );
68	
69	const mainItemsBasePremium = (items: Item[]): number =>
70	  sumOver(items.filter(isMainItem), unitPriceFor);
71	
72	const totalBasePremium = (items: Item[]): number =>
73	  mainItemsBasePremium(items) + componentsBasePremium(items);
74	
75	const isHighlyEnchanted = (item: Item): boolean =>
76	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
77	
78	const itemSurchargeRate = (item: Item): number =>
79	  (item.cursed ? CURSE_SURCHARGE_RATE : 0) +
80	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_RATE : 0);
81	
82	const itemSurcharges = (item: Item): number =>
83	  unitPriceFor(item) * itemSurchargeRate(item);
84	
85	const totalSurcharges = (items: Item[]): number =>
86	  sumOver(items, itemSurcharges);
87	
88	const firstInsuranceSurcharge = (policyBase: number): number =>
89	  policyBase * FIRST_INSURANCE_RATE;
90	
91	const isLoyal = (customer: Customer): boolean =>
92	  customer.yearsWithMHPCO >= LOYALTY_MIN_YEARS;
93	
94	const loyaltyDiscount = (policyBase: number, customer: Customer): number =>
95	  isLoyal(customer) ? policyBase * LOYALTY_RATE : 0;
96	
97	const followUpDiscount = (policyBase: number, isFollowUp: boolean): number =>
98	  isFollowUp ? policyBase * FOLLOW_UP_RATE : 0;
99	
100	const policyWideAdjustment = (
101	  policyBase: number,
102	  customer: Customer,
103	  isFollowUp: boolean
104	): number =>
105	  firstInsuranceSurcharge(policyBase) -
106	  loyaltyDiscount(policyBase, customer) -
107	  followUpDiscount(policyBase, isFollowUp);
108	
109	const roundPremiumInMHPCOsFavor = (premium: number): number =>
110	  Math.ceil(premium);
111	
112	export const quote = (input: QuoteInput, context: QuoteContext = {}): number => {
113	  const policyBase = totalBasePremium(input.items);
114	  const premiumBeforeFee =
115	    policyBase +
116	    totalSurcharges(input.items) +
117	    policyWideAdjustment(policyBase, input.customer, context.isFollowUp ?? false);
118	  return roundPremiumInMHPCOsFavor(premiumBeforeFee + PROCESSING_FEE);
119	};
